function GalleryContent() {
  const [activeFilter, setActiveFilter] = useState<ArtifactType | "all">("all")
  const [searchQuery, setSearchQuery] = useState("")
  const [isPending, startTransition] = useTransition()

  const debouncedSearch = useDebounce(searchQuery, 200)

  // Calculate counts for each filter
  const counts = useMemo(() => {
    const filteredBySearch = searchQuery
      ? sampleArtifacts.filter(a => 
          a.tags.some(tag => tag.toLowerCase().includes(debouncedSearch.toLowerCase())) ||
          a.title.toLowerCase().includes(debouncedSearch.toLowerCase())
        )
      : sampleArtifacts

    return {
      all: filteredBySearch.length,
      pdf: filteredBySearch.filter(a => a.type === "pdf").length,
      image: filteredBySearch.filter(a => a.type === "image").length,
      html: filteredBySearch.filter(a => a.type === "html").length,
    }
  }, [debouncedSearch, searchQuery])

  // Filter artifacts based on active filter and search
  const filteredArtifacts = useMemo(() => {
    let filtered = sampleArtifacts

    // Apply type filter
    if (activeFilter !== "all") {
      filtered = filtered.filter(a => a.type === activeFilter)
    }

    // Apply search filter
    if (debouncedSearch) {
      filtered = filtered.filter(a => 
        a.tags.some(tag => tag.toLowerCase().includes(debouncedSearch.toLowerCase())) ||
        a.title.toLowerCase().includes(debouncedSearch.toLowerCase())
      )
    }

    return filtered
  }, [activeFilter, debouncedSearch])

  const handleFilterChange = useCallback((filter: ArtifactType | "all") => {
    startTransition(() => {
      setActiveFilter(filter)
    })
  }, [])

  const handleClearFilters = useCallback(() => {
    setActiveFilter("all")
    setSearchQuery("")
  }, [])

  const handlePublish = useCallback(() => {
    console.log("Publish clicked")
  }, [])

  return (
    <div className="min-h-screen bg-background transition-colors duration-300">
      <Header onPublish={handlePublish} />

      <main className="container mx-auto px-4 md:px-6 lg:px-8 py-8">
        {/* Page header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold tracking-tight text-foreground mb-2">
            Gallery
          </h1>
          <p className="text-muted-foreground">
            Browse and manage your generated artifacts
          </p>
        </div>

        {/* Filters and search */}
        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-8">
          <FilterTabs
            activeFilter={activeFilter}
            onFilterChange={handleFilterChange}
            counts={counts}
            isLoading={isPending}
          />
          <TagSearch
            value={searchQuery}
            onChange={setSearchQuery}
            className="w-full sm:w-64"
          />
        </div>

        {/* Results area */}
        <div className="relative min-h-[400px]">
          {/* Loading overlay */}
          {isPending && (
            <div className="absolute inset-0 bg-background/50 backdrop-blur-sm z-10 flex items-center justify-center rounded-lg">
              <div className="flex items-center gap-2 text-muted-foreground">
                <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                <span className="text-sm font-medium">Loading...</span>
              </div>
            </div>
          )}

          {/* Empty state */}
          {filteredArtifacts.length === 0 && !isPending && (
            <EmptyState
              title="No artifacts found"
              description={
                searchQuery
                  ? `No artifacts match "${searchQuery}". Try a different search term.`
                  : "No artifacts match the selected filter."
              }
              actionLabel="Clear filters"
              onAction={handleClearFilters}
            />
          )}

          {/* Artifact grid */}
          {filteredArtifacts.length > 0 && (
            <div className={cn(
              "grid gap-5",
              "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3",
              isPending && "opacity-50 pointer-events-none"
            )}>
              {filteredArtifacts.map((artifact, index) => (
                <div
                  key={artifact.id}
                  className="animate-in fade-in slide-in-from-bottom-4"
                  style={{ animationDelay: `${index * 50}ms`, animationFillMode: "both" }}
                >
                  <ArtifactCard artifact={artifact} />
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Results count */}
        {filteredArtifacts.length > 0 && (
          <div className="mt-8 text-center text-sm text-muted-foreground">
            Showing {filteredArtifacts.length} of {sampleArtifacts.length} artifacts
          </div>
        )}
      </main>
    </div>
  )
}

