"use client"

import { cn } from "@/lib/utils"
import { FileText, Image, Code, Layers } from "lucide-react"
import { ArtifactType } from "./artifact-card"

interface FilterTabsProps {
  activeFilter: ArtifactType | "all"
  onFilterChange: (filter: ArtifactType | "all") => void
  counts: Record<ArtifactType | "all", number>
  isLoading?: boolean
}

const filters: { value: ArtifactType | "all"; label: string; icon: typeof Layers }[] = [
  { value: "all", label: "All", icon: Layers },
  { value: "pdf", label: "PDF", icon: FileText },
  { value: "image", label: "Image", icon: Image },
  { value: "html", label: "HTML", icon: Code },
]

export function FilterTabs({ activeFilter, onFilterChange, counts, isLoading }: FilterTabsProps) {
  return (
    <div className="flex items-center gap-1 p-1 rounded-lg bg-secondary/50 border border-border">
      {filters.map(({ value, label, icon: Icon }) => {
        const isActive = activeFilter === value
        const count = counts[value]

        return (
          <button
            key={value}
            onClick={() => onFilterChange(value)}
            disabled={isLoading}
            className={cn(
              "relative flex items-center gap-2 px-3.5 py-2 rounded-md text-sm font-medium",
              "transition-all duration-200 ease-out",
              "focus:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
              "disabled:opacity-50 disabled:cursor-not-allowed",
              "cursor-pointer",
              isActive
                ? "bg-card text-foreground shadow-sm"
                : "text-muted-foreground hover:text-foreground hover:bg-secondary/80"
            )}
          >
            <Icon className={cn(
              "h-4 w-4 transition-colors",
              isActive && "text-primary"
            )} />
            <span>{label}</span>
            <span className={cn(
              "px-1.5 py-0.5 text-xs rounded-md min-w-[20px] text-center",
              "transition-colors duration-200",
              isActive 
                ? "bg-primary/10 text-primary" 
                : "bg-muted text-muted-foreground"
            )}>
              {count}
            </span>
          </button>
        )
      })}
    </div>
  )
}

