@import "tailwindcss";
@import "tw-animate-css/dist/tw-animate.css";

@custom-variant dark (&:is(.dark *));

/* ============================================
   OPTION 1: Clean SaaS Dashboard (Default)
   Inspired by Linear, Vercel, Stripe
   ============================================ */
:root,
.theme-saas {
  --background: oklch(0.07 0 0);
  --foreground: oklch(0.98 0 0);
  --card: oklch(0.12 0 0);
  --card-foreground: oklch(0.98 0 0);
  --popover: oklch(0.12 0 0);
  --popover-foreground: oklch(0.98 0 0);
  --primary: oklch(0.72 0.14 180);
  --primary-foreground: oklch(0.07 0 0);
  --secondary: oklch(0.18 0 0);
  --secondary-foreground: oklch(0.85 0 0);
  --muted: oklch(0.18 0 0);
  --muted-foreground: oklch(0.65 0 0);
  --accent: oklch(0.72 0.14 180);
  --accent-foreground: oklch(0.07 0 0);
  --destructive: oklch(0.62 0.24 25);
  --destructive-foreground: oklch(0.98 0 0);
  --border: oklch(0.22 0 0);
  --input: oklch(0.18 0 0);
  --ring: oklch(0.72 0.14 180);
  --radius: 0.75rem;
}

/* ============================================
   OPTION 2: Creative Artifact Gallery
   Visual, expressive, gradient accents
   ============================================ */
.theme-creative {
  --background: oklch(0.10 0.01 280);
  --foreground: oklch(0.98 0 0);
  --card: oklch(0.14 0.015 280);
  --card-foreground: oklch(0.98 0 0);
  --popover: oklch(0.14 0.015 280);
  --popover-foreground: oklch(0.98 0 0);
  --primary: oklch(0.75 0.18 200);
  --primary-foreground: oklch(0.10 0 0);
  --secondary: oklch(0.20 0.02 280);
  --secondary-foreground: oklch(0.85 0 0);
  --muted: oklch(0.20 0.02 280);
  --muted-foreground: oklch(0.65 0.02 280);
  --accent: oklch(0.70 0.20 320);
  --accent-foreground: oklch(0.98 0 0);
  --destructive: oklch(0.62 0.24 25);
  --destructive-foreground: oklch(0.98 0 0);
  --border: oklch(0.26 0.03 280);
  --input: oklch(0.18 0.02 280);
  --ring: oklch(0.75 0.18 200);
  --radius: 1rem;
}

/* ============================================
   OPTION 3: Developer Documentation Style
   Calm, technical, optimized for scanning
   ============================================ */
.theme-docs {
  --background: oklch(0.97 0 0);
  --foreground: oklch(0.15 0 0);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.15 0 0);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.15 0 0);
  --primary: oklch(0.55 0.15 250);
  --primary-foreground: oklch(0.98 0 0);
  --secondary: oklch(0.94 0 0);
  --secondary-foreground: oklch(0.25 0 0);
  --muted: oklch(0.94 0 0);
  --muted-foreground: oklch(0.45 0 0);
  --accent: oklch(0.55 0.15 250);
  --accent-foreground: oklch(0.98 0 0);
  --destructive: oklch(0.55 0.22 25);
  --destructive-foreground: oklch(0.98 0 0);
  --border: oklch(0.90 0 0);
  --input: oklch(0.94 0 0);
  --ring: oklch(0.55 0.15 250);
  --radius: 0.5rem;
}

/* ============================================
   OPTION 4: Premium Workspace Style
   Elegant, polished, sophisticated
   ============================================ */
.theme-premium {
  --background: oklch(0.98 0.005 60);
  --foreground: oklch(0.18 0.01 60);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.18 0.01 60);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.18 0.01 60);
  --primary: oklch(0.55 0.12 45);
  --primary-foreground: oklch(0.98 0 0);
  --secondary: oklch(0.95 0.01 60);
  --secondary-foreground: oklch(0.30 0.01 60);
  --muted: oklch(0.95 0.01 60);
  --muted-foreground: oklch(0.50 0.02 60);
  --accent: oklch(0.55 0.12 45);
  --accent-foreground: oklch(0.98 0 0);
  --destructive: oklch(0.55 0.20 25);
  --destructive-foreground: oklch(0.98 0 0);
  --border: oklch(0.90 0.01 60);
  --input: oklch(0.95 0.01 60);
  --ring: oklch(0.55 0.12 45);
  --radius: 0.875rem;
}

@theme inline {
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground;
  }
  button,
  [role="button"],
  label[for],
  summary {
    cursor: pointer;
  }
  :focus-visible {
    outline: 2px solid var(--ring);
    outline-offset: 2px;
    border-radius: 4px;
  }
}

/* Card hover glow effect */
.card-glow {
  position: relative;
}

.card-glow::before {
  content: '';
  position: absolute;
  inset: -1px;
  border-radius: inherit;
  padding: 1px;
  background: linear-gradient(135deg, transparent 0%, var(--primary) 50%, transparent 100%);
  opacity: 0;
  transition: opacity 0.3s ease;
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  pointer-events: none;
}

.card-glow:hover::before {
  opacity: 0.5;
}

/* Skeleton shimmer */
@keyframes shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}

.skeleton-shimmer {
  background: linear-gradient(
    90deg,
    var(--muted) 25%,
    var(--secondary) 50%,
    var(--muted) 75%
  );
  background-size: 200% 100%;
  animation: shimmer 1.5s ease-in-out infinite;
}

/* Fade-in-up card animation */
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(10px); }
  to   { opacity: 1; transform: translateY(0); }
}

.animate-fade-in-up {
  animation: fadeInUp 0.3s ease-out forwards;
}

/* Custom scrollbar */
::-webkit-scrollbar { width: 8px; height: 8px; }
::-webkit-scrollbar-track { background: var(--background); }
::-webkit-scrollbar-thumb { background: var(--muted); border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: var(--muted-foreground); }

