3	import { useState, useRef } from "react";
4	import Link from "next/link";
5	import type { ArtifactType, ArtifactVisibility } from "@/types";
6	
7	function inferType(file: File): ArtifactType | null {
8	  if (file.type === "application/pdf" || file.name.endsWith(".pdf")) return "pdf";
9	  if (file.type.startsWith("image/")) return "image";
10	  if (
11	    file.type === "text/html" ||
12	    file.name.endsWith(".html") ||
13	    file.name.endsWith(".htm")
14	  )
15	    return "html";
16	  return null;
17	}
18	
19	async function fileToBase64(file: File): Promise<string> {
20	  return new Promise((resolve, reject) => {
21	    const reader = new FileReader();
22	    reader.onload = () => {
23	      const dataUrl = reader.result as string;
24	      resolve(dataUrl.split(",")[1]);
25	    };
26	    reader.onerror = reject;
27	    reader.readAsDataURL(file);
28	  });
29	}
30	
31	interface SuccessState {
32	  visibility: ArtifactVisibility;
33	  artifactId: string;
34	  shareToken?: string;
35	}
36	
37	export function PublishForm() {
38	  const [title, setTitle] = useState("");
39	  const [description, setDescription] = useState("");
40	  const [tags, setTags] = useState("");
41	  const [visibility, setVisibility] = useState<ArtifactVisibility>("public");
42	  const [file, setFile] = useState<File | null>(null);
43	  const [uploading, setUploading] = useState(false);
44	  const [error, setError] = useState("");
45	  const [success, setSuccess] = useState<SuccessState | null>(null);
46	  const fileRef = useRef<HTMLInputElement>(null);
47	
48	  async function handleSubmit(e: React.FormEvent) {
49	    e.preventDefault();
50	    if (!file) { setError("Please select a file."); return; }
51	    if (!title.trim()) { setError("Title is required."); return; }
52	
53	    const type = inferType(file);
54	    if (!type) {
55	      setError("Unsupported file type. Please upload a PDF, image, or HTML file.");
56	      return;
57	    }
58	
59	    setUploading(true);
60	    setError("");
61	
62	    try {
63	      const file_base64 = await fileToBase64(file);
64	
65	      const res = await fetch("/api/artifacts", {
66	        method: "POST",
67	        headers: { "Content-Type": "application/json" },
68	        body: JSON.stringify({
69	          title: title.trim(),
70	          description: description.trim() || undefined,
71	          tags: tags
72	            .split(",")
73	            .map((t) => t.trim())
74	            .filter(Boolean),
75	          type,
76	          mime_type: file.type,
77	          visibility,
78	          file_base64,
79	          filename: file.name,
80	        }),
81	      });
