"use client";

import { useState, useRef } from "react";
import Link from "next/link";
import type { ArtifactType, ArtifactVisibility } from "@/types";

function inferType(file: File): ArtifactType | null {
  if (file.type === "application/pdf" || file.name.endsWith(".pdf")) return "pdf";
  if (file.type.startsWith("image/")) return "image";
  if (
    file.type === "text/html" ||
    file.name.endsWith(".html") ||
    file.name.endsWith(".htm")
  )
    return "html";
  return null;
}

async function fileToBase64(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const dataUrl = reader.result as string;
      resolve(dataUrl.split(",")[1]);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

interface SuccessState {
  visibility: ArtifactVisibility;
  artifactId: string;
  shareToken?: string;
}

export function PublishForm() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [tags, setTags] = useState("");
  const [visibility, setVisibility] = useState<ArtifactVisibility>("public");
  const [file, setFile] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState<SuccessState | null>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!file) { setError("Please select a file."); return; }
    if (!title.trim()) { setError("Title is required."); return; }

    const type = inferType(file);
    if (!type) {
      setError("Unsupported file type. Please upload a PDF, image, or HTML file.");
      return;
    }

    setUploading(true);
    setError("");

    try {
      const file_base64 = await fileToBase64(file);

      const res = await fetch("/api/artifacts", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          title: title.trim(),
          description: description.trim() || undefined,
          tags: tags
            .split(",")
            .map((t) => t.trim())
            .filter(Boolean),
          type,
          mime_type: file.type,
          visibility,
          file_base64,
          filename: file.name,
        }),
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error ?? "Upload failed");
      }

      const data = await res.json();
      setSuccess({
        visibility,
        artifactId: data.artifact.id,
        shareToken: data.shareLink?.token,
      });
    } catch (err) {
      setError(err instanceof Error ? err.message : "Something went wrong");
    } finally {
      setUploading(false);
    }
  }

  function reset() {
    setSuccess(null);
    setTitle("");
    setDescription("");
    setTags("");
    setFile(null);
    setError("");
    if (fileRef.current) fileRef.current.value = "";
