2	import { uploadArtifact } from "@/lib/storage";
3	import type { Artifact, ArtifactType, ArtifactVisibility, CreateArtifactBody, ServiceResult } from "@/types";
4	
5	export async function listArtifacts({
6	  type,
7	  tags,
8	  visibility,
9	  limit = 50,
10	  offset = 0,
11	}: {
12	  type?: ArtifactType;
13	  tags?: string[];
14	  visibility?: ArtifactVisibility;
15	  limit?: number;
16	  offset?: number;
17	} = {}): Promise<ServiceResult<Artifact[]>> {
18	  const supabase = createAdminClient();
19	  let query = supabase
20	    .from("artifacts")
21	    .select("*")
22	    .order("created_at", { ascending: false })
23	    .range(offset, offset + limit - 1);
24	
25	  if (visibility) query = query.eq("visibility", visibility);
26	  if (type) query = query.eq("type", type);
27	  if (tags && tags.length > 0) query = query.overlaps("tags", tags);
28	
29	  const { data, error } = await query;
30	  if (error) return { ok: false, status: 500, message: error.message };
31	  return { ok: true, data: (data ?? []) as Artifact[] };
32	}
33	
34	export async function getArtifact(id: string): Promise<ServiceResult<Artifact>> {
35	  const supabase = createAdminClient();
36	  const { data, error } = await supabase
37	    .from("artifacts")
38	    .select("*")
39	    .eq("id", id)
40	    .single();
41	
42	  if (error) {
43	    if (error.code === "PGRST116") return { ok: false, status: 404, message: "Artifact not found" };
44	    return { ok: false, status: 500, message: error.message };
45	  }
46	  return { ok: true, data: data as Artifact };
47	}
